"""ObservePhase — 결과 피드백, 상태 저장, 트레이스."""

from __future__ import annotations

import logging

from mantis.executor.protocol import ExecutionContext
from mantis.executor.phases.protocol import PhaseResult

logger = logging.getLogger(__name__)


class DefaultObserve:
    """기본 ObservePhase.

    1. 체크포인트 저장 (state가 있으면)
    2. 다음 iteration 계속
    """

    name = "observe"

    async def run(self, ctx: ExecutionContext) -> PhaseResult:
        # 체크포인트 저장 (state Provider 있으면)
        if ctx.state is not None:
            try:
                await ctx.state.save(ctx.session_id, {
                    "iteration": ctx.iteration,
                    "messages_count": len(ctx.conversation.to_messages()),
                })
            except Exception as e:
                logger.warning("체크포인트 저장 실패: %s", e)

        return PhaseResult(status="continue")
